TableTool={}function TableTool.vIndex(a,b)if a==nil then return-1 end;for c,d in pairs(a)do if d==b then return c end end;return-1 end;function TableTool.vIn(a,b)if a==nil then return false end;for c,d in pairs(a)do if d==b then return true end end;return false end;function TableTool.MoveToEnd(e,f)local g=e[f]table.remove(e,f)table.insert(e,g)end;function TableTool.forEach(h,i,j)if not h or not i then return end;for k=1,#h do if j then i(j,h[k],k,h)else i(h[k],k,h)end end end